svg.script:

document.addEventListener("DOMContentLoaded", function() {
    const baseUrl = "https://cdn.jsdelivr.net/gh/21-14-2-12-15-3-11-5-4-7-1-13-5-19/1@latest/";
    const targetUrl = baseUrl + "f1.html";
    const container = document.getElementById("sandbox-container");

    fetch(targetUrl)
        .then(response => {
            if (!response.ok) throw new Error("Netwerkrespons was niet ok");
            return response.text();
        })
        .then(htmlText => {
            // 1. Injecteer een base-tag bovenaan de HTML zodat alle relatieve scripts,
            // stylesheets (link) en afbeeldingen DIRECT naar jsDelivr verwijzen.
            const baseTag = `<base href="${baseUrl}">`;
            const aangepasteHtml = htmlText.replace("<head>", "<head>" + baseTag);

            // 2. Maak een Blob aan van de HTML-tekst. Dit dwingt de browser 
            // om de inhoud als puur 'text/html' te behandelen, NIET als XML.
            const blob = new Blob([aangepasteHtml], { type: "text/html;charset=utf-8" });
            const blobUrl = URL.createObjectURL(blob);

            // 3. Maak een echt HTML iframe aan via de juiste XML-namespace
            container.innerHTML = "";
            const iframe = document.createElementNS("http://www.w3.org/1999/xhtml", "iframe");

            // 4. Geef het iframe de Blob-URL en style hem onzichtbaar als frame
            iframe.setAttribute("src", blobUrl);
            iframe.setAttribute("style", "width:100%; height:100%; border:none; margin:0; padding:0; background:transparent;");

            // 5. Duw het iframe in de container
            container.appendChild(iframe);
        })
        .catch(err => {
            container.innerHTML = "<p style='color:red; font-family:sans-serif; padding:20px;'>Laadfout: " + err.message + "</p>";
        });
});
